import { useState } from "react";
import { Select, Stack, Text, FormControl, FormLabel } from "@chakra-ui/react";

const countries = [
  {
    name: "India",
    states: ["Delhi", "Goa", "Gujarat", "Maharashtra", "Tamil Nadu"],
  },
  {
    name: "United States",
    states: ["California", "Texas", "Florida", "New York", "Washington"],
  },
];

const DynamicSelect = () => {
  const [selectedCountry, setSelectedCountry] = useState("");
  const [selectedState, setSelectedState] = useState("");

  const handleCountryChange = (e) => {
    setSelectedCountry(e.target.value);
    setSelectedState("");
  };

  const handleStateChange = (e) => {
    setSelectedState(e.target.value);
  };

  const getStatesByCountry = () => {
    const country = countries.find((c) => c.name === selectedCountry);
    return country ? country.states : [];
  };

  return (
    <Stack spacing={5} mt={3}>
      {/* Country */}
      <FormControl>
        <FormLabel fontWeight="600" color="#1c1d1f">
          Country
        </FormLabel>
        <Select
          placeholder="Select Country"
          value={selectedCountry}
          onChange={handleCountryChange}
          bg="white"
          borderRadius="md"
          border="1px solid #d1d7dc"
          _hover={{ borderColor: "#A435F0" }}
          _focus={{
            borderColor: "#A435F0",
            boxShadow: "0 0 0 1px #A435F0",
          }}
        >
          {countries.map((country, index) => (
            <option key={index} value={country.name}>
              {country.name}
            </option>
          ))}
        </Select>
      </FormControl>

      {/* State */}
      <FormControl isDisabled={!selectedCountry}>
        <FormLabel fontWeight="600" color="#1c1d1f">
          State / Region
        </FormLabel>
        <Select
          placeholder="Select State"
          value={selectedState}
          onChange={handleStateChange}
          bg="white"
          borderRadius="md"
          border="1px solid #d1d7dc"
          _hover={{ borderColor: "#A435F0" }}
          _focus={{
            borderColor: "#A435F0",
            boxShadow: "0 0 0 1px #A435F0",
          }}
        >
          {getStatesByCountry().map((state, index) => (
            <option key={index} value={state}>
              {state}
            </option>
          ))}
        </Select>
      </FormControl>
    </Stack>
  );
};

export default DynamicSelect;
